    size_t offset = 0;
    size_t len = strlen(s);

    while (offset < len && regexec(&regex, s + offset, 1, pmatch, 0) == 0) {
        if (result == NULL) {
            result = (char *)malloc(len + 1);
            strncpy(result, s, offset + pmatch[0].rm_so);
            result[offset + pmatch[0].rm_so] = '\0';
        }
        strcat(result, "***");
        offset += pmatch[0].rm_eo;
        strncat(result, s + offset, len - offset);
    }

